import functions_framework
import hashlib
import hmac
import json
import os
from flask import jsonify

WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET', 'your-secret-key-here')

def verify_webhook_signature(payload, signature_header):
    """Verify the webhook signature using HMAC SHA256"""
    if not signature_header:
        return False
    
    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode('utf-8'),
        payload.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(expected_signature, signature_header)

def process_payment_event(event_data):
    """Process the payment webhook event"""
    event_type = event_data.get('type')
    payment_id = event_data.get('payment_id')
    
    if event_type == 'payment.successful':
        print(f"Payment {payment_id} successful")
    elif event_type == 'payment.failed':
        print(f"Payment {payment_id} failed")
    elif event_type == 'payment.refunded':
        print(f"Payment {payment_id} refunded")
    else:
        print(f"Unknown event type: {event_type}")
    
    return True

@functions_framework.http
def webhook_handler(request):
    """HTTP Cloud Function for payment webhooks"""
    
    if request.method != 'POST':
        return jsonify({'error': 'Method not allowed'}), 405
    
    signature = request.headers.get('X-Webhook-Signature', '')
    
    try:
        request_data = request.get_data(as_text=True)
        
        if not verify_webhook_signature(request_data, signature):
            return jsonify({'error': 'Invalid signature'}), 401
        
        event_data = json.loads(request_data)
        
        if 'type' not in event_data or 'payment_id' not in event_data:
            return jsonify({'error': 'Invalid payload'}), 400
        
        success = process_payment_event(event_data)
        
        if success:
            return jsonify({'status': 'success', 'message': 'Webhook processed'}), 200
        else:
            return jsonify({'error': 'Processing failed'}), 500
            
    except json.JSONDecodeError:
        return jsonify({'error': 'Invalid JSON'}), 400
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500